INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('0c1ffe72244e06d3', 'WV', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in West Virginia?', '["Are West Virginia primaries open or closed?","Can unaffiliated voters participate in the WV primary?","West Virginia primary voting rules"]', 'West Virginia utilizes a semi-closed primary system. By default, a voter must be registered with a political party to vote in that party''s primary. However, state law allows each recognized political party''s state executive committee to decide whether to permit unaffiliated voters to request their ballot. In recent cycles, the Democratic Party has allowed unaffiliated voters to participate, while the Republican Party has kept its primary strictly closed.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State - Primary Elections', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('5e3868108e425d98', 'WV', '["federal","state","county"]', 'runoff_rules', 'Does West Virginia hold primary runoff elections?', '["What is the threshold to win a primary in WV?","Does West Virginia require a majority to win a primary?","West Virginia primary runoff rules"]', 'No. West Virginia does not hold primary runoff elections. A candidate does not need to secure a 50%+1 majority to win the party''s nomination; the candidate who receives a simple plurality of the votes in the primary advances directly to the general election.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All primary candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('f2229b38ef88f4e0', 'WV', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in West Virginia?', '["Do write-in votes count in WV?","How to register as a write-in candidate in West Virginia","Write-in filing deadline WV"]', 'Yes, but they must officially register. To have their votes tabulated in the general election, a write-in candidate must file a formal Write-in Candidate''s Certificate of Announcement with the Secretary of State (for state/federal) or County Clerk (for local) no later than 49 days before the election.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State - Candidate Guides', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('db7e896303412662', 'WV', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for West Virginia in 2026?', '["When do candidates file for office in West Virginia?","West Virginia filing deadline 2026","January filing deadline WV"]', 'To appear on the 2026 primary ballot, all major party candidates must file their Certificate of Announcement during the official filing period, which runs from the second Monday in January to midnight on the last Saturday in January. For the 2026 cycle, the deadline was January 31, 2026.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State - Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('89d2d255a044d802', 'WV', '["federal","state","county"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in West Virginia?', '["Independent candidate ballot access West Virginia","Running without a party in WV 2026","How many signatures for independent US Senate WV"]', 'Independent candidates must submit a petition to appear on the general election ballot. By statute, the petition must contain valid signatures of registered voters equal to at least 1% of the total number of votes cast for that specific office in the last preceding election, but no less than 25 signatures. The deadline to file is August 1.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7f8192d88fafc50b', 'WV', '["federal","state","county"]', 'ballot_access', 'Does West Virginia have a sore loser law?', '["Can I run as an independent if I lose the WV primary?","West Virginia sore loser statute","General election ballot access after primary defeat WV"]', 'Yes. West Virginia strictly enforces a sore loser law under W.Va. Code § 3-5-23. A candidate who seeks a party''s nomination in a primary election and is defeated cannot subsequently have their name placed on the general election ballot as an independent candidate or as a write-in candidate for the same office.', 'https://code.wvlegislature.gov/3-5-23/', 'West Virginia Code § 3-5-23', '2026-05-17', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('61bf6982c1969190', 'WV', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in West Virginia?', '["West Virginia joint ticket rules","How are Lt Gov candidates selected in WV?","Does the Governor pick a running mate in West Virginia?"]', 'No, because West Virginia does not elect a Lieutenant Governor. By state statute, the President of the State Senate automatically holds the title of Lieutenant Governor and is first in the line of succession to the governorship. The position is chosen internally by the State Senate, not by the voters.', 'https://www.wvlegislature.gov/', 'West Virginia Legislature', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('38dcefd8d466a4a2', 'WV', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in West Virginia for 2026?', '["West Virginia primary date 2026","When is Election Day 2026 in West Virginia?","May primary West Virginia"]', 'The West Virginia primary election will be held on Tuesday, May 12, 2026. The general election will be held on Tuesday, November 3, 2026. Polls are open from 6:30 a.m. to 7:30 p.m. local time.', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State - Election Dates', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('6388bd58e1795950', 'WV', '["state"]', 'election_dates', 'Is Governor Patrick Morrisey running for re-election in 2026?', '["West Virginia Governor election 2026","Who is defending the WV Governor seat?","Is Patrick Morrisey on the 2026 ballot?"]', 'No. West Virginia elects its Governor strictly on the presidential election cycle. Governor Patrick Morrisey (R) was elected in 2024, and his four-year term runs through early 2029. There is no gubernatorial race on the 2026 midterm ballot.', 'https://sos.wv.gov/', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('f4b2af6f59c91b76', 'WV', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in West Virginia in 2026?', '["Is Shelley Moore Capito up for re-election in 2026?","When is Jim Justice''s next election?","West Virginia US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat currently held by Shelley Moore Capito (R) is up for election in 2026. Senator Jim Justice (Class 1) was elected in 2024 and will not appear on the ballot again until 2030.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('b785ad24107cba16', 'WV', '["federal"]', 'election_dates', 'How many U.S. House districts are in West Virginia for the 2026 election?', '["West Virginia congressional apportionment","Are all WV congressional seats up in 2026?","Number of US Representatives from West Virginia"]', 'West Virginia is apportioned 2 U.S. House districts. Both seats are on the 2026 ballot. The state''s delegation was reduced from 3 to 2 districts following the 2020 census reapportionment.', 'https://sos.wv.gov/', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('c488489823a9d4e8', 'WV', '["state"]', 'election_dates', 'Which West Virginia State Legislature seats are up for election in 2026?', '["Are all West Virginia House seats up in 2026?","West Virginia Senate election cycle 2026","Which legislative districts are on the ballot in WV?"]', 'All 100 seats in the West Virginia House of Delegates (2-year terms) are up for election in 2026. The West Virginia State Senate has 34 members serving 4-year staggered terms; in 2026, 17 of those seats (half the chamber) will be on the ballot.', 'https://www.wvlegislature.gov/', 'West Virginia Legislature', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('876747cef37b550f', 'WV', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in West Virginia in 2026?', '["Is the Attorney General up in 2026?","WV statewide election list 2026","When is the Secretary of State election in WV?"]', 'None. West Virginia elects all of its statewide executive officers (including Governor, Attorney General, Secretary of State, Treasurer, Auditor, and Commissioner of Agriculture) concurrently on the presidential election cycle (e.g., 2024, 2028). There are no statewide executive races on the 2026 midterm ballot.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('ea8a98b540d16fa4', 'WV', '["judicial"]', 'election_dates', 'How are West Virginia Supreme Court justices selected and when are they elected?', '["West Virginia judicial elections 2026","Are WV judges elected or appointed?","Nonpartisan judicial elections West Virginia"]', 'West Virginia Supreme Court of Appeals Justices are elected to 12-year terms in nonpartisan elections. Crucially, these nonpartisan judicial elections are held during the May primary election, not the November general election. The candidate who receives the most votes in May wins the seat outright.', 'http://www.courtswv.gov/', 'West Virginia Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7f4cab2781f6a852', 'WV', '["state"]', 'election_dates', 'What is the schedule for the West Virginia State Legislature sessions?', '["When does the WV legislature meet?","West Virginia 60 day legislative session","Is the West Virginia legislature full time?"]', 'The West Virginia Legislature is a part-time body that meets annually for 60 consecutive days. In standard years, the session begins on the second Wednesday in January. However, in the year following a gubernatorial election (e.g., 2025, 2029), the regular 60-day session begins later, on the second Wednesday in February.', 'https://www.wvlegislature.gov/', 'West Virginia Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('76f0a4b54033fd1d', 'WV', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of West Virginia?', '["Age and residency for West Virginia Governor","West Virginia Constitution Governor qualifications","Who is eligible to be Governor of WV?"]', 'Under Article IV, Section 4 of the West Virginia Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States, and a resident of West Virginia for at least five years preceding the election.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State - Candidate Qualifications', '2026-05-17', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('d1a48f0e37326eb2', 'WV', '["state"]', 'candidate_eligibility', 'What are the qualifications and term limits for the West Virginia State Legislature?', '["Qualifications for WV State Delegate","Age requirement West Virginia State Senate","West Virginia legislature term limit status"]', 'A candidate for the State Senate must be at least 25 years old. A candidate for the House of Delegates must be at least 18 years old. Both must be citizens of West Virginia and residents of their district for at least one year prior to the election. West Virginia does NOT impose term limits on state legislators.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('221ecd0e2296ca29', 'WV', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in West Virginia?', '["US Senate residency requirements West Virginia","Age to run for Congress in West Virginia","Federal constitutional requirements for WV candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('957bb191abbf8cc3', 'WV', '["state"]', 'candidate_eligibility', 'What are the term limits for the West Virginia Governor?', '["How many terms can a West Virginia Governor serve?","Patrick Morrisey term limits WV","West Virginia executive term limit law"]', 'Under the West Virginia Constitution, the Governor is limited to serving two consecutive four-year terms. After serving two consecutive terms, an individual is ineligible to run for the office again until a full four-year term has intervened.', 'https://ballotpedia.org/Governor_of_West_Virginia', 'West Virginia Constitution', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('addf315702d66178', 'WV', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General in West Virginia?', '["Qualifications to run for Attorney General in WV","Do I need to be a member of the bar to be WV AG?","Legal requirements for West Virginia Attorney General"]', 'Under Article IV, Section 4 of the West Virginia Constitution, the Attorney General must be at least 25 years old at the beginning of their term, a citizen of the state for five years preceding the election, and a licensed attorney authorized to practice law in West Virginia.', 'https://sos.wv.gov/elections', 'West Virginia Constitution Article IV, Section 4', '2026-05-17', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('2670789a815f6a26', 'WV', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in West Virginia?', '["West Virginia county clerk qualifications","Can I run for county commissioner in WV?","County residency for WV officials"]', 'To run for a county office (such as County Commissioner, Assessor, or Sheriff) in West Virginia, a candidate must be a qualified voter (at least 18 years old) and a resident of the county (and the specific magisterial district, if applicable) prior to the election.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State - Local Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('26090aa9927f62b2', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in West Virginia?', '["West Virginia voter ID requirements","Do I need my driver''s license to vote in WV?","Acceptable ID for West Virginia voting"]', 'Yes, but it is not a strict photo ID state. West Virginia law requires voters to show a valid form of identification, which includes photo IDs (like a driver''s license) AND non-photo IDs (like a utility bill, bank statement, or Medicare card). Alternatively, a voter can be identified by an election official or cast a provisional ballot if they sign an affidavit.', 'https://sos.wv.gov/elections/Pages/BeReg.aspx', 'West Virginia Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('efc96ad6aa89bb65', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'Is West Virginia a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in West Virginia?","West Virginia vote-by-mail system","Do I need an excuse to vote absentee in WV?"]', 'No. West Virginia is NOT a universal mail ballot state and strictly prohibits no-excuse mail-in absentee voting. A registered voter must satisfy a specific statutory excuse to request a mail-in ballot, such as illness, physical disability, being out of the county for work/travel during early voting and Election Day, or working long hours.', 'https://sos.wv.gov/elections/Pages/AbsenteeVoting.aspx', 'West Virginia Secretary of State - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('5c31c693235b90e6', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'Does West Virginia offer early in-person voting?', '["Can I vote early in person in WV?","West Virginia early voting dates 2026","When does early voting start in West Virginia?"]', 'Yes. West Virginia offers a robust no-excuse early in-person voting period. All registered voters may cast a ballot early beginning on the 13th day before the election and ending on the 3rd day before the election (the Saturday prior to Election Day).', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7575fed20dea711d', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does West Virginia offer same-day registration?', '["Last day to register to vote in WV","West Virginia same day voter registration","Voter registration deadline 2026 West Virginia"]', 'The deadline to register to vote in West Virginia is 21 days before the election. Registration can be completed online, by mail, or in person. West Virginia DOES NOT offer same-day voter registration at the polls.', 'https://sos.wv.gov/elections/Pages/GoVoteWV.aspx', 'West Virginia Secretary of State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('023384dbbd02cce7', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in West Virginia?', '["How close can I campaign to a polling place in WV?","West Virginia 100 feet electioneering rule","WV buffer zone around voting centers"]', 'Under West Virginia law (W.Va. Code § 3-9-9), electioneering is strictly prohibited within 100 feet of the outside entrance of the building housing a polling place. This bans distributing campaign literature, displaying signs, or soliciting votes within this zone.', 'https://code.wvlegislature.gov/3-9-9/', 'West Virginia Code § 3-9-9', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('63ebab645d826dde', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in West Virginia?', '["Can felons vote in West Virginia state?","Felony voting rights restoration WV","Voting on parole in West Virginia"]', 'In West Virginia, individuals convicted of a felony lose their voting rights. To have them restored automatically, they must fully complete their sentence, which includes serving any prison time and completing all periods of probation and parole. Once completed, they may re-register to vote.', 'https://sos.wv.gov/elections/Pages/BeReg.aspx', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('d2a226847725a68a', 'WV', '["county"]', 'voter_interaction', 'How many counties are in West Virginia, and why does it matter for campaigns?', '["West Virginia county election administration","How many county clerks in WV?","Local election control West Virginia"]', 'West Virginia has 55 counties. Election administration is handled at the county level by County Clerks, who manage voter registration, early voting sites, and absentee ballot processing. Statewide campaigns must coordinate logistics across these 55 separate administrative jurisdictions.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('e99d0f1408c0c816', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the West Virginia voter file?', '["West Virginia voter database access cost","How to get the voter list in WV","What data is included in the West Virginia voter file?"]', 'Campaigns and political committees can purchase the statewide voter registration list from the Secretary of State. The data request requires a fee, and the file includes voter names, addresses, and voting history, but its use is legally restricted to political and election-related purposes.', 'https://sos.wv.gov/elections', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7168bf607147378f', 'WV', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in West Virginia for the 2026 cycle?', '["Are there contribution limits in West Virginia?","WV individual donation caps 2026 election","How much can I donate to a candidate in West Virginia?"]', 'West Virginia enforces contribution limits that are periodically adjusted for inflation. For the current 2025-2026 cycle, individuals may contribute up to $2,800 per election to a candidate for statewide or legislative office. The primary and general elections are considered separate, allowing a donor to give $2,800 for each.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State - Campaign Finance FAQ', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('c5ef6c4447458c5e', 'WV', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in West Virginia campaigns?', '["Corporate contribution ban West Virginia state","Can a business donate to my campaign in WV?","Corporate campaign finance rules West Virginia"]', 'No. Under West Virginia law, direct contributions from the general treasury of a corporation or labor union to a candidate''s campaign committee are strictly PROHIBITED. Corporations and unions may only participate by establishing and administering a separate Political Action Committee (PAC) funded by voluntary employee donations.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('3a0c73b530aca86a', 'WV', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in West Virginia?', '["Where do I file campaign finance reports in WV?","What is the West Virginia Ethics Commission?","Does the WV Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in West Virginia are administered directly by the West Virginia Secretary of State''s Office. All state and legislative candidates must register their committees and file their contribution and expenditure reports electronically through the Secretary''s online Campaign Finance Reporting System (CFRS).', 'https://sos.wv.gov/elections/Pages/CampaignFinance.aspx', 'West Virginia Secretary of State - Campaign Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('18dc0667593612f9', 'WV', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for West Virginia candidates?', '["WV SOS filing dates 2026","When are campaign finance reports due in WV?","West Virginia pre-primary and pre-general report deadlines"]', 'In an election year, candidate committees must file quarterly reports. Additionally, candidates participating in an election must file critical pre-election reports due 15 days before the primary and 15 days before the general election.', 'https://sos.wv.gov/elections/Pages/CampaignFinance.aspx', 'West Virginia Secretary of State - Reporting Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('3fc058061e24e8cc', 'WV', '["state","county","municipal"]', 'finance_ethics', 'What are West Virginia''s rapid disclosure requirements for late contributions?', '["West Virginia 48-hour large contribution report","Late contribution reporting West Virginia SOS","When do I file a rapid report in WV?"]', 'West Virginia imposes rapid reporting requirements on outside spending rather than candidate contributions. Under SB 622, independent expenditures of $1,000 or more made near an election trigger immediate reporting requirements to the Secretary of State.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('05400845c3ba5aac', 'WV', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in West Virginia?', '["WV personal use prohibition campaign finance","Can I use campaign money for personal items in WV?","Prohibited expenditures West Virginia"]', 'Yes. Under West Virginia law, campaign funds cannot be converted to personal use. Expenditures must bear a direct relationship to the candidate''s campaign or the ordinary and necessary expenses of holding public office.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('a1bea157efc17296', 'WV', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for West Virginia legislators?', '["Can West Virginia legislators raise money during session?","Lobbyist contribution ban WV legislature","Legislative session contribution rules West Virginia"]', 'No. West Virginia DOES NOT impose a strict ''session freeze'' banning legislators from accepting campaign contributions during the regular session. However, W.Va. Code § 3-8-15 does impose a rapid disclosure requirement: any legislator holding a fundraising event during the session must disclose the event and all received contributions within 48 hours to the Secretary of State.', 'https://code.wvlegislature.gov/3-8-15/', 'West Virginia Code § 3-8-15', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('fed33256d265ac06', 'WV', '["federal","state"]', 'redistricting', 'Who draws West Virginia''s congressional and state legislative maps?', '["Does the WV legislature draw district maps?","Who has the authority to draw district lines in West Virginia?","West Virginia redistricting commission"]', 'In West Virginia, the state legislature holds the exclusive authority to draw and enact both congressional and state legislative district boundaries. The maps are passed as regular legislation and are subject to the Governor''s signature or veto.', 'https://ballotpedia.org/Redistricting_in_West_Virginia', 'Ballotpedia - Redistricting in West Virginia', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('6ea21987f25f205b', 'WV', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in West Virginia?', '["Standards for drawing West Virginia district lines","West Virginia gerrymandering rules","Map requirements WV"]', 'Under the West Virginia Constitution, state legislative districts must be formed of contiguous territory, be compact, and be as nearly equal in population as possible. The state constitution also requires that county boundaries be respected and counties not be split when forming districts to the extent practicable.', 'https://ballotpedia.org/Redistricting_in_West_Virginia', 'West Virginia Constitution', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('21c9e11cbf797fc6', 'WV', '["state"]', 'redistricting', 'Are the current West Virginia state legislative maps operative for the 2026 cycle?', '["Status of West Virginia Senate redistricting maps","Are there pending redistricting lawsuits in West Virginia?","West Virginia 2026 state legislative boundaries"]', 'Yes. The redistricting maps enacted by the West Virginia legislature following the 2020 census remain fully operative for the 2026 election cycle. There are no ongoing systemic legal challenges preventing their use.', 'https://www.wvlegislature.gov/', 'West Virginia Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('b7321c44985ade5f', 'WV', '["federal"]', 'redistricting', 'What is the status of West Virginia''s congressional map for the 2026 cycle?', '["Is the WV congressional map operative for 2026?","West Virginia congressional redistricting controversy","How many districts did WV lose?"]', 'The congressional map enacted by the legislature is fully operative for the 2026 cycle. Following the 2020 census, West Virginia lost one congressional seat due to slow population growth, reducing its U.S. House delegation from three to two districts. The resulting two-district map faces no active litigation.', 'https://ballotpedia.org/Redistricting_in_West_Virginia', 'Ballotpedia - Redistricting in West Virginia', '2026-05-17', 'static', 'secondary_source', 'Federal candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('af409902e0eb85f6', 'WV', '["state"]', 'recall_rules', 'Does West Virginia have a recall mechanism for state officials?', '["Can the Governor of West Virginia be recalled?","How to recall a state senator in WV","Statewide recall election rules West Virginia"]', 'No. The State of West Virginia does not have any legal or constitutional mechanism for the recall of state-level elected officials, including the Governor, statewide executives, or members of the state legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_West_Virginia', 'Laws governing recall in West Virginia', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('a4c0562b1e331297', 'WV', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in West Virginia?', '["West Virginia county commissioner recall rules","Signature requirement local recall West Virginia","Recalling a mayor in WV"]', 'West Virginia does not have a general statutory recall process for county or municipal officials. Recall is highly restricted and is only permitted in a narrow subset of municipalities if their specific, state-approved local city charter explicitly authorizes the recall process.', 'https://ballotpedia.org/Laws_governing_recall_in_West_Virginia', 'Laws governing recall in West Virginia', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7cb1ee327b98572c', 'WV', '["state"]', 'ballot_access', 'Does West Virginia have a citizen initiative process?', '["How to get an initiative on the WV ballot","West Virginia citizen initiative signature requirements","Can citizens propose laws in West Virginia?"]', 'No. West Virginia is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to force them onto the ballot. All statewide ballot measures must be referred by the state legislature.', 'https://ballotpedia.org/Initiative_and_referendum_in_West_Virginia', 'Ballotpedia - Initiative and Referendum in West Virginia', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7e1804155a6a3b4a', 'WV', '["state"]', 'ballot_access', 'How does the West Virginia legislature refer a constitutional amendment to the voters?', '["Legislative referral process West Virginia","Referendum by legislature WV","Can the WV legislature put a constitutional amendment on the ballot?"]', 'The West Virginia State Legislature can refer a constitutional amendment to the ballot by securing a two-thirds (66.67%) supermajority vote in both the House of Delegates and the State Senate during a single legislative session. It does not require the Governor''s signature to appear on the general election ballot.', 'https://ballotpedia.org/Amending_the_West_Virginia_Constitution', 'West Virginia Constitution Article XIV', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('4459cd32a0df04c3', 'WV', '["state"]', 'ballot_access', 'Does West Virginia have a veto referendum process?', '["How to refer a WV bill to the ballot","West Virginia citizen referendum rules","Veto referendum signature threshold West Virginia state"]', 'No. West Virginia does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_West_Virginia', 'Ballotpedia - Initiative and Referendum in West Virginia', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('b06d7908d0fb7b20', 'WV', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in West Virginia?', '["West Virginia ballot measure pass threshold","Does a measure need a supermajority in WV?","Majority vote requirements West Virginia ballot measures"]', 'In West Virginia, a legislatively referred constitutional amendment requires only a simple majority (over 50%) of the total votes cast on that specific measure to pass and become part of the state constitution.', 'https://ballotpedia.org/Amending_the_West_Virginia_Constitution', 'West Virginia Constitution Article XIV', '2026-05-17', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('c70f8e4a00571cfe', 'WV', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in West Virginia?', '["Requirements to run for WV Secretary of State","Who can run for Secretary of State in WV?","Residency rules for West Virginia SOS"]', 'Under Article IV, Section 4 of the West Virginia Constitution, a candidate for Secretary of State must be a citizen entitled to vote, meaning they must be at least 18 years of age. Additionally, they must have been a resident of West Virginia for at least five years preceding the election.', 'https://ballotpedia.org/West_Virginia_Secretary_of_State', 'West Virginia Constitution Article IV, Section 4', '2026-05-17', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('097853bc58af9816', 'WV', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in West Virginia?', '["Eligibility for West Virginia State Treasurer","Who can run for State Treasurer in WV?","West Virginia Treasurer residency requirements"]', 'Under the West Virginia Constitution, the qualifications for State Treasurer are identical to those for the Secretary of State: a candidate must be a citizen entitled to vote (at least 18 years old) and a resident of West Virginia for at least five years preceding the election.', 'https://sos.wv.gov/', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('40ea1181a328d708', 'WV', '["state"]', 'candidate_eligibility', 'Is the State Auditor an elected office in West Virginia, and what are the qualifications?', '["What does the WV Auditor do?","Qualifications for West Virginia Auditor","Is the Auditor elected in WV?"]', 'Yes. The State Auditor is a statewide elected constitutional officer. Under Article IV, Section 4 of the West Virginia Constitution, candidates must be citizens entitled to vote (at least 18 years of age) and residents of the state for at least five years preceding the election.', 'https://sos.wv.gov/', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('e99a4ff24aabe6e8', 'WV', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in West Virginia?', '["Run for school board West Virginia requirements","Who can be a school board member in WV?","School board residency rules West Virginia"]', 'To run for a local school board in West Virginia, candidates must be at least 18 years old, a qualified voter, and a resident of the district they seek to represent. Additionally, they must possess a high school diploma or a GED, and they must undergo mandatory training prior to taking office.', 'https://www.berkeleywv.org/DocumentCenter/View/11754/Running-for-Office-in-Berkeley-County-PDF', 'West Virginia Local Candidate Guides', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('63b1bf1ede4d372f', 'WV', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for West Virginia Supreme Court justices?', '["West Virginia Supreme Court Justice eligibility","Years of practice required for WV Supreme Court","Are West Virginia judges elected or appointed?"]', 'West Virginia Supreme Court of Appeals Justices are elected in statewide nonpartisan elections. Candidates must be at least 30 years old, a citizen of West Virginia for five years prior to the election, in good standing with the state bar, and admitted to practice law for at least 10 years prior to the election.', 'https://sos.wv.gov/media/407/download?inline=', 'West Virginia Secretary of State - Candidate Certificate of Announcement', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('e6de1e0330e8d770', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in West Virginia?', '["How to fix a rejected signature in WV","West Virginia ballot cure process deadline","Missing signature on WV mail ballot"]', 'West Virginia law does not currently provide a statutory signature cure process. If an absentee ballot return envelope is missing a signature or the signature is rejected during the verification process, the ballot is generally challenged and rejected without guaranteeing the voter a post-election window to fix the error.', 'https://www.vote411.org/west-virginia', 'VOTE411 - West Virginia', '2026-05-17', 'static', 'secondary_source', 'Voters and Campaigns', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('f298342ef51ffb5c', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in West Virginia?', '["When are military ballots due in West Virginia?","UOCAVA return deadline WV","Overseas voting rules West Virginia state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. West Virginia provides a secure electronic portal for returning these ballots. If submitted electronically, they must be received by the close of polls on Election Day. If mailed, they must be postmarked by Election Day and received by the start of the canvass (6 days later).', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State - GoVoteWV', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('3e46cabb83efab9a', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in West Virginia?', '["What is a provisional ballot in WV?","Voting without ID West Virginia","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s eligibility is in question, such as their name not appearing in the poll book, their signature not matching the registration record, or if they fail to present an acceptable form of identification at the polls.', 'https://www.vote411.org/west-virginia', 'VOTE411 - West Virginia', '2026-05-17', 'static', 'secondary_source', 'Voters and Poll Watchers', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('a58a3fe410e1634b', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'Does West Virginia have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the West Virginia DMV?","WV motor voter automatic registration","Do I have to register to vote if I get a WV driver''s license?"]', 'Yes. West Virginia implemented Automatic Voter Registration (AVR) following legislation passed in 2016 (effective in 2021). Eligible citizens who apply for or renew a driver''s license or state ID card at the DMV are automatically registered to vote or have their address updated, unless they affirmatively decline (opt-out) via a back-end post-transaction mailer.', 'https://www.ncsl.org/elections-and-campaigns/automatic-voter-registration', 'NCSL - Automatic Voter Registration', '2026-05-17', 'static', 'secondary_source', 'Voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('8bbd0cb036d4e074', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'Does West Virginia offer Online Voter Registration?', '["Can I register to vote online in WV?","West Virginia electronic voter registration","GoVoteWV online registration portal"]', 'Yes. Eligible West Virginia residents with a valid state driver''s license or non-driver ID card can register to vote or update their registration securely using the Secretary of State''s GoVoteWV online voter registration portal. The deadline is 21 days prior to an election.', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State - GoVoteWV', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('d0815ce58e13cae9', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'How does West Virginia maintain its voter registration lists?', '["WV voter list maintenance rules","How are inactive voters handled in West Virginia?","West Virginia voter roll cleaning process"]', 'West Virginia conducts list maintenance using National Change of Address (NCOA) data, returned undeliverable mail, and death records. The state has also recently engaged in pilot programs using commercial credit data (like Experian) to identify ''Best Addresses''. Voters who fail to respond to confirmation notices and do not vote in two consecutive federal general elections are purged from the rolls under NVRA guidelines.', 'https://www.eac.gov/sites/default/files/2025-08/Voter_List_Maintenance_Study_508.pdf', 'U.S. Election Assistance Commission - Voter List Maintenance Report', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('88df9fdfcd782baf', 'WV', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in West Virginia?', '["When is the last day to mail my ballot in WV?","West Virginia mail ballot postmark deadline","What time are ballots due in West Virginia?"]', 'West Virginia provides two deadlines depending on the return method. If hand-delivered to the County Clerk''s office, the ballot must be received by the day BEFORE Election Day. If returned by mail, the ballot must be postmarked by Election Day and received no later than the start of the canvass, which is 6 days following the election.', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State - Election Dates', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('f2ed64094632ea72', 'WV', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in West Virginia?', '["Does West Virginia use ranked choice voting?","RCV status in West Virginia 2026","Instant runoff voting WV"]', 'No. Ranked Choice Voting (RCV) is strictly prohibited in West Virginia. During the 2025 legislative session, the state legislature passed SB 500, which officially banned the use of Ranked Choice Voting for any local, state, or federal election in the state.', 'https://www.wvlegislature.gov/', 'West Virginia Legislature (SB 500 - 2025)', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('c412d56dbfc0f528', 'WV', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in West Virginia elections?', '["How are tied elections decided in West Virginia?","Tie-breaker rules West Virginia elections","What happens if a race is tied in WV?"]', 'In the rare event of an exact tie in a West Virginia election, state law (W.Va. Code § 3-6-12) dictates that the tie is broken by the casting of lots. The process is overseen by the Governor (for statewide/district offices) or the county board of canvassers (for local offices).', 'https://code.wvlegislature.gov/3-6-12/', 'West Virginia Code § 3-6-12', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('63116861d4abc118', 'WV', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on West Virginia campaign materials?', '["West Virginia ''Paid for by'' rules","Campaign ad disclaimer requirements WV","Political taglines West Virginia SOS"]', 'West Virginia campaign finance law requires that all political advertising (print, broadcast, and digital) clearly display a ''Paid for by'' disclaimer. The disclaimer must identify the candidate, committee, or individual that authorized and financed the communication.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('9d95c77aa1b68e19', 'WV', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in West Virginia?', '["WV campaign coordination rules","When is a PAC expenditure not independent in West Virginia?","Prohibition on candidate-PAC coordination WV"]', 'An independent expenditure becomes ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. Once coordinated, the expenditure is treated as an in-kind contribution and is subject to the strict $2,800 contribution limit.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('57f9c8121867e20f', 'WV', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in West Virginia?', '["WV SOS late fee","Penalty for missing a West Virginia campaign finance deadline","Secretary of State fine for late filing WV"]', 'The West Virginia Secretary of State assesses civil penalties for late campaign finance reports. Campaigns that miss filing deadlines are subject to a fine of $10 per day, which accrues for each day the report remains unfiled, up to the statutory maximum.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('6820233a26269a80', 'WV', '["state","county","municipal"]', 'finance_ethics', 'When and how must a West Virginia campaign committee terminate?', '["Closing a West Virginia campaign committee","SOS committee termination requirements","Final campaign finance report West Virginia"]', 'A candidate committee may formally terminate when it has achieved a zero cash balance, legally disposed of all unexpended funds, and resolved all outstanding debts or loans. A formal Final Report marking the campaign account as closed must be filed with the Secretary of State.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('8cdb70e72ddcd61c', 'WV', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in West Virginia?', '["WV independent expenditure reporting SOS","Disclosure for WV independent expenditure groups","Reporting thresholds for outside spending West Virginia"]', 'Any person, PAC, or organization making an independent expenditure of more than $1,000 for electioneering communications must file an independent expenditure report with the Secretary of State. Due to a 2019 law (SB 622), this applies widely to political broadcasts and advertising.', 'https://www.wvlegislature.gov/', 'West Virginia Legislature (SB 622)', '2026-05-17', 'static', 'statute_citation', 'Independent groups and PACs', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('4d7f843a38181ed7', 'WV', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in West Virginia?', '["West Virginia in-kind contribution valuation rules","Reporting non-monetary donations West Virginia campaign","Fair market value for in-kind gifts WV"]', 'In-kind contributions (donated goods, services, or equipment) must be reported at their reasonable fair market value. They count directly toward the donor''s $2,800 per-election monetary contribution limits.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('7640b0ada236b9f7', 'WV', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in West Virginia?', '["West Virginia candidate personal loan limits","Can I pay myself back for a campaign loan in WV?","Reporting candidate loans in SOS"]', 'No. A candidate may loan or contribute an UNLIMITED amount of their own personal funds to their campaign committee; these funds are exempt from contribution limits. Loans must be properly documented on disclosures and may be repaid from campaign contributions raised during the cycle.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State - Campaign Finance FAQ', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('a2eab173508a02a3', 'WV', '["state","county","municipal"]', 'finance_ethics', 'What can West Virginia candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in WV?","WV surplus campaign funds rules","Donating remaining campaign funds West Virginia"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign, return them pro-rata to contributors, transfer them to a recognized political party, or donate them to an IRS-recognized tax-exempt charitable organization.', 'https://sos.wv.gov/campaign-finance-frequently-asked-questions', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('dba031acadf36910', 'WV', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in West Virginia?', '["WV PAC donation limits to candidates 2026","Political committee vs individual contribution limit West Virginia","Maximum PAC gift to state legislator WV"]', 'In West Virginia, Political Action Committees (PACs) are subject to the EXACT SAME contribution limits as individuals. For the 2026 cycle, a PAC is capped at donating $2,800 per election to a candidate for statewide or legislative office.', 'https://ballotpedia.org/Campaign_finance_requirements_in_West_Virginia', 'Ballotpedia / West Virginia Secretary of State', '2026-05-17', 'static', 'secondary_source', 'State and County candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('33d2af3ba897d5f5', 'WV', '["judicial"]', 'finance_ethics', 'Does West Virginia provide public financing for state campaigns?', '["Public matching funds for West Virginia Governor","State funded campaigns West Virginia status","Government campaign grants WV Supreme Court"]', 'West Virginia generally does not provide public financing for standard state or legislative campaigns. However, it does operate the West Virginia Supreme Court of Appeals Public Campaign Financing Pilot Program (W.Va. Code § 3-12), offering public funds to participating judicial candidates who agree to strict contribution limits.', 'https://code.wvlegislature.gov/pdf/3-12/', 'West Virginia Code § 3-12', '2026-05-17', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('49c0bc40216d97e4', 'WV', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in West Virginia?', '["When are county sheriffs elected in WV?","West Virginia county official term lengths","Are county commissions on the 2026 ballot?"]', 'Elected county officials in West Virginia—including County Commissioners, Sheriffs, Assessors, and Prosecuting Attorneys—serve four-year or six-year terms depending on the specific office. Most county executive offices are elected concurrently with the presidential election cycle (2024, 2028), while County Commission seats are staggered.', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('f6ee9a13ff01ca8d', 'WV', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for West Virginia elections?', '["When are West Virginia election results official?","WV certification deadline","County canvass start date West Virginia"]', 'By law, the county board of canvassers must convene on the 6th day following the election (the Monday after a Tuesday election) to begin canvassing the returns. This allows the inclusion of mail ballots postmarked by Election Day. Once completed, the results are certified and sent to the Secretary of State.', 'https://sos.wv.gov/govotewv', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T18-24-02_west_virginia_full_v1'),
  ('f27234b789684cc6', 'WV', '["federal","state"]', 'election_dates', 'When and how are special elections called in West Virginia?', '["West Virginia special election timeline","Who calls a special election to fill a US House vacancy in WV?","Filling a midterm vacancy West Virginia"]', 'Special elections to fill federal or certain state legislative vacancies are called by a proclamation from the Governor. The Governor sets the exact dates for the special primary and general election to ensure adequate time for candidate filing, ballot printing, and absentee voting.', 'https://sos.wv.gov/', 'West Virginia Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T18-24-02_west_virginia_full_v1')
